module counter_4bit (
    input clk,
    input reset,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    // Counter logic
    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end

endmodule
